class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

public class Solution {
    public TreeNode str2tree(String s) {
        MyInteger idx = new MyInteger(0);
        return str2treeHelper(s, idx);
    }

    private TreeNode str2treeHelper(String s, MyInteger idx) {
        if (idx.get() >= s.length()) return null;

        int sign = 1;
        if (s.charAt(idx.get()) == '-') {
            sign = -1;
            idx.increment();
        }

        int num = 0;
        while (idx.get() < s.length() && Character.isDigit(s.charAt(idx.get()))) {
            num = num * 10 + (s.charAt(idx.get()) - '0');
            idx.increment();
        }

        TreeNode node = new TreeNode(sign * num);

        if (idx.get() < s.length() && s.charAt(idx.get()) == '(') {
            idx.increment();
            node.left = str2treeHelper(s, idx);
            idx.increment();
        }
        if (idx.get() < s.length() && s.charAt(idx.get()) == '(') {
            idx.increment();
            node.right = str2treeHelper(s, idx);
            idx.increment();
        }

        return node;
    }
}

class MyInteger {
    private int value;

    MyInteger(int value) {
        this.value = value;
    }

    int get() {
        return value;
    }

    void increment() {
        value++;
    }
}
```


